import azure.functions as func
import json

def main(req: func.HttpRequest) -> func.HttpResponse:
    # Get request method for logging or specific handling if needed
    method = req.method

    # Example response data
    response_data = {
        "message": f"Hello from Azure Functions! You made a {method} request.",
        "timestamp": func.get_timestamp().isoformat()
    }

    # Create the HTTP response
    res = func.HttpResponse(
        json.dumps(response_data),
        mimetype="application/json",
        status_code=200
    )

    # Configure CORS headers
    # Allow requests from any origin (*)
    res.headers['Access-Control-Allow-Origin'] = '*'
    # Allow specific methods (GET, POST, OPTIONS, etc.)
    res.headers['Access-Control-Allow-Methods'] = 'GET, POST, OPTIONS'
    # Allow specific headers (Content-Type, Authorization, etc.)
    res.headers['Access-Control-Allow-Headers'] = 'Content-Type'
    # Allow credentials if needed (e.g., cookies, authorization headers)
